@module ccManager  src=ccManager.lua  loc=52  sha=c1012ac  mode=chunk  self=ccm

# Invariants & contracts
  @invariant  the node exists iff a producer claims it; release reaps it when the last claim drops  @ 4
  @contract  claim pins the node at index 0, records the producer's claim, returns 0  @ 6
  @contract  release drops the claim; returns the surviving node index, or nil if it reaped/absent  @ 7
  @reaper  TrackFX_AddByName/CopyToTrack/Delete; node = fx_type JS with fx_ident 'Continuum CC'  @ 8

# Shapes
  @shape  claims = { [producer:str] = { [trackGuid:str] = MediaTrack } }  @ 5

# Private state
  @state CC_ADDNAME = 'JS:Continuum CC'  @ 10
  @state CC_IDENT = 'Continuum CC'  @ 11
  @state ccm = {}  @ 13
  @state claims = {}  @ 14   -- producer -> { guid -> track }

# Private functions
  @fn nodeIndex(track)  @ 17-25
      -- fx_ident for a JSFX is the bare Effects-relative path (cf. routingManager fxIdentAt)

# Public API (ccm:*)
  @api ccm:claim(producer, track)  @ 27-40
  @api ccm:release(producer, track)  @ 42-50

# REAPER API surface
  @reaper TrackFX_GetCount, TrackFX_GetNamedConfigParm, TrackFX_AddByName, TrackFX_CopyToTrack, TrackFX_Delete
  @reaper GetTrackGUID
